# Utility module: String and List utilities using classes with callable interfaces

class StringValidator:
    _min_length: int
    _max_length: int

    def __init__(self, min_len: int, max_len: int):
        self._min_length = min_len
        self._max_length = max_len

    def is_valid(self, s: str) -> bool:
        return self._min_length <= len(s) <= self._max_length

    def validate(self, s: str) -> bool:
        return self.is_valid(s)


class ListScaler:
    _factor: int

    def __init__(self, scale: int):
        self._factor = scale

    def scale(self, x: int) -> int:
        return x * self._factor

    @static
    def identity(x: int) -> int:
        return x

    def apply_to_list(self, items: list[int]) -> list[int]:
        result: list[int] = []
        for item in items:
            result.append(self.scale(item))
        return result

