# Math utilities: Higher-order functions using class-based function objects

class GreaterThanComparator:
    def compare(self, a: int, b: int) -> bool:
        return a > b

class LessThanComparator:
    def compare(self, a: int, b: int) -> bool:
        return a < b

class Doubler:
    def transform(self, x: int) -> int:
        return x * 2

class Tripler:
    def transform(self, x: int) -> int:
        return x * 3

class StartsWithA:
    def check(self, s: str) -> bool:
        if len(s) == 0:
            return False
        return str(s[0]) == "a"

class LengthChecker:
    def check(self, s: str) -> bool:
        return len(s) > 0


def find_best(items: list[int], cmp) -> int:
    if len(items) == 0:
        return 0
    best: int = items[0]
    for i in range(1, len(items)):
        if cmp.compare(items[i], best):
            best = items[i]
    return best


def composite_transform(x: int, t1, t2) -> int:
    return t2.transform(t1.transform(x))


def process_strings(strings: list[str], pred) -> int:
    count: int = 0
    for s in strings:
        if pred.check(s):
            count += 1
    return count
